package ch.post.it.evoting.verifier.block.block3.loader.offline;

import com.scytl.products.ov.mixnet.commons.ballots.ElGamalEncryptedBallot;
import com.scytl.products.ov.mixnet.commons.mathematical.impl.ZpElement;
import org.junit.Assert;
import org.junit.Test;

import java.math.BigInteger;

public class OfflineVoterWithProofLoaderTest {

    @Test
    public void convert() {
        ElGamalEncryptedBallot ballot = OfflineVoterWithProofLoader.convertToEncryptedBallot("\"[{\"\"value\"\":,\"\"p\"\":,\"\"q\"\":},{\"\"value\"\":,\"\"p\"\":,\"\"q\"\":}]\"");
        Assert.assertNotNull(ballot.getGamma());
        Assert.assertEquals(1, ballot.getPhis().size());
    }

    @Test
    public void getProofs() {
        OfflineVoterWithProofLoader.convertToProof("\"{\"\"zkProof\"\":{\"\"hash\"\":\"\"AJwOPoTxxVubcFgnIY8KiHwMmBFbrYD6of1C5iP/sI3K\"\",\"\"values\"\":[\"\"\"\"],\"\"q\"\":\"\"\"\"}}\"", new ZpElement(BigInteger.ONE, null) {
        });
    }
}